module ripple_carry_adder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] S,
    output Cout
);
    wire [3:0] borrow;

    assign S[0] = A[0] ^ B[0] ^ Cin;
    assign borrow[0] = (A[0] & B[0]) | (Cin & (A[0] ^ B[0]));

    assign S[1] = A[1] ^ B[1] ^ borrow[0];
    assign borrow[1] = (A[1] & B[1]) | (borrow[0] & (A[1] ^ B[1]));

    assign S[2] = A[2] ^ B[2] ^ borrow[1];
    assign borrow[2] = (A[2] & B[2]) | (borrow[1] & (A[2] ^ B[2]));

    assign S[3] = A[3] ^ B[3] ^ borrow[2];
    assign Cout = (A[3] & B[3]) | (borrow[2] & (A[3] ^ B[3]));
endmodule
